import Duration from "duration";
import pluralize from "pluralize";
import classNames from "classnames";
import { bool, string, instanceOf } from "prop-types";

import dateFormatShape from "../../../shapes/dateFormatShape";

import styles from "./DateRange.scss";

const DEFAULT_FORMAT = {
  year: "numeric",
  month: "short",
};

class DateRange extends React.Component {
  static propTypes = {
    className: string,
    start: instanceOf(Date).isRequired,
    end: instanceOf(Date),
    format: dateFormatShape,
    showDuration: bool,
    separator: string,
  }

  static defaultProps = {
    className: null,
    format: DEFAULT_FORMAT,
    showDuration: false,
    separator: "·",
  }

  render() {
    const { start, end, format, className } = this.props;

    return (
      <span className={classNames(styles.dateRange, className)}>
        {start.toLocaleDateString("en-US", format)}
        -
        {end ? end.toLocaleDateString("en-US", format) : "Present"}
        {this.renderDuration()}
      </span>
    );
  }

  renderDuration = () => {
    if (!this.props.showDuration) {
      return null;
    }

    return (
      <React.Fragment>
        {" "}({this.getDuration()})
      </React.Fragment>
    );
  }

  getDuration = () => {
    const { year, month } = new Duration(this.props.start, this.props.end || new Date());

    const parts = []

    if (year > 0) {
      parts.push(pluralize("yr", year, true));
    }

    if (month > 0) {
      parts.push(pluralize("mo", month, true));
    }

    return parts.join(" ");
  }
}

export default DateRange;
